(8, 188, 2, 1, 'Familial 120€', '<p></p><table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"374\" style=\"width: 281pt;\"><tbody><tr height=\"160\" style=\"height:120.0pt\"><td height=\"160\" class=\"xl65\" width=\"374\" style=\"height:120.0pt;width:281pt\"><ul><li>50 kg  broken fragrant rice</li><li>10 L of oil</li><li>10 kg sugar</li><li>2 large pots of concentrated  tomato</li><li>120 Maggie cubes</li><li>1 big box of coffee</li><li>1 box of chocopoudre</li><li>1 big pot of  margarine</li><li>1 big pot of mustard</li><li>1 jar of mayonnaise</li><li>1 big pot of chocolate to  spread</li><li>10 boxes of corned beef</li><li>2 kg milk powder</li><li>3 kg of pasta</li><li>5 big soaps</li><li>2 kg  laundry</li><li>2 L of bleach<br></li></ul></td></tr></tbody></table><p></p>', 'null', 'familial_12075889.png', 120.00, 120.00, 108.00, 114.00, 1, 0.00, 0.00, NULL, NULL, 1, '1', 0, 0, 1, 10, '{\"product_name\":{\"de\":\"Familial 120\\u20ac\",\"fr\":\"Familial 120\\u20ac\"},\"product_desc\":{\"de\":\"<p> <\\/ p> <ul> <li> 50kg Reis <\\/ li> <li> duftend gebrochen 10l <\\/ li> <li> \\u00d6l 10kg Zucker <\\/ li> <li> in St\\u00fcck 2 gro\\u00dfe T\\u00f6pfe <\\/ li> <li> konzentrierte Tomate 120 W\\u00fcrfel <\\/ li> <li> 1 gro\\u00dfe Schachtel Kaffee <\\/ li> <li> 1 Schachtel Schokopudding <\\/ li> <li> 1 gro\\u00dfer Topf Margarine <\\/ li> <li> 1 gro\\u00dfes Glas Senf <\\/ li> <li> 1 Glas Mayonnaise <\\/ li> <li> 1 gro\\u00dfes Glas Schokoladenaufstrich <\\/ li> <li> 10 Schachtel Corned Beef <\\/ li> < li> 2kg Milchpulver <\\/ li> <li> 3 kg Nudeln <\\/ li> <li> 5 gro\\u00dfe Seifen <\\/ li> <li> 2kg W\\u00e4sche <\\/ li> <li> 2L Bleichmittel <br> <\\/ li> <\\/ ul> <p> <\\/ p>\",\"fr\":\"<p><\\/p><ul><li>50kg riz\\u00a0<\\/li><li>parfum\\u00e9 bris\\u00e9 10l\\u00a0<\\/li><li>d\'huile 10kg sucre\\u00a0<\\/li><li>en morceau 2 gros pots de\\u00a0<\\/li><li>tomate concentr\\u00e9e 120 cubes\\u00a0<\\/li><li>1 grosse bo\\u00eete de caf\\u00e9\\u00a0<\\/li><li>1 boi